import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
import spray.json.DefaultJsonProtocol._
import scala.concurrent.ExecutionContextExecutor
import scala.util.{Failure, Success}

case class UrlRequest(urls: List[String])
case class UrlResponse(url: String, content: String, status: Int)

object UrlRequestJsonProtocol extends DefaultJsonProtocol {
  implicit val urlRequestFormat = jsonFormat1(UrlRequest)
  implicit val urlResponseFormat = jsonFormat3(UrlResponse)
}

object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher
  
  import UrlRequestJsonProtocol._
  
  val http = Http()
  
  val route =
    post {
      entity(as[UrlRequest]) { urlRequest =>
        val responses = urlRequest.urls.map { url =>
          val request = HttpRequest(uri = url)
          http.singleRequest(request).map { response =>
            Unmarshal(response.entity).to[String].map { content =>
              UrlResponse(url, content, response.status.intValue())
            }
          }
        }
        
        onComplete(Future.sequence(responses)) {
          case Success(results) => complete(results)
          case Failure(ex) => complete(StatusCodes.InternalServerError, ex.getMessage)
        }
      }
    }
  
  val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
  
  println("Server online at http://localhost:8080/")
}